public async Task ProcessTicketPurchase(int eventId, int purchaseQuantity)
{
    using (var context = new EventContext())
    {
        var eventEntity = await context.Events
            .Include(e => e.Tickets)
            .SingleOrDefaultAsync(e => e.Id == eventId);

        if (eventEntity == null) throw new Exception("Event not found");

        using (var transaction = await context.Database.BeginTransactionAsync(IsolationLevel.Serializable))
        {
            if (eventEntity.Tickets.Available < purchaseQuantity)
            {
                throw new Exception("Not enough tickets available");
            }

            eventEntity.Tickets.Available -= purchaseQuantity;

            context.Entry(eventEntity).State = EntityState.Modified;

            await context.SaveChangesAsync();

            transaction.Commit();
        }
    }
